// Prometheus 쿼리 URL 및 현재 시간대(hour_bucket) 구성
const item = $input.first().json;
const systemName = item.system_name;
const job = item.prometheus_job || '';
const collectorType = item.collector_type;
const metricGroup = item.metric_group;

// 현재 시각 기준 1시간 전 (집계 대상 시간대)
const now = new Date();
now.setMinutes(0, 0, 0);
const hourEnd = now.getTime() / 1000;  // Unix timestamp
const hourStart = hourEnd - 3600;

// 시간대 bucket (ISO 형식)
const hourBucket = new Date(hourEnd * 1000);
hourBucket.setMinutes(0, 0, 0);
const hourBucketISO = hourBucket.toISOString();

// collector_type + metric_group별 PromQL 매핑
const QUERIES = {
  'node_exporter': {
    'cpu': {
      cpu_avg: `avg_over_time(node_cpu_usage_percent{system_name="${systemName}"}[1h])`,
      cpu_max: `max_over_time(node_cpu_usage_percent{system_name="${systemName}"}[1h])`,
      cpu_min: `min_over_time(node_cpu_usage_percent{system_name="${systemName}"}[1h])`,
      cpu_p95: `quantile_over_time(0.95, node_cpu_usage_percent{system_name="${systemName}"}[1h])`,
      iowait:  `avg_over_time(node_cpu_iowait_percent{system_name="${systemName}"}[1h])`
    },
    'memory': {
      mem_used_pct:  `avg_over_time(node_memory_used_percent{system_name="${systemName}"}[1h])`,
      mem_p95:       `quantile_over_time(0.95, node_memory_used_percent{system_name="${systemName}"}[1h])`,
      mem_avail_gb:  `min_over_time(node_memory_available_bytes{system_name="${systemName}"}[1h]) / 1073741824`
    },
    'disk': {
      disk_util_pct: `avg_over_time(node_disk_utilization_percent{system_name="${systemName}"}[1h])`,
      disk_read_iops:`avg_over_time(node_disk_reads_completed_total{system_name="${systemName}"}[1h])`,
      disk_write_iops:`avg_over_time(node_disk_writes_completed_total{system_name="${systemName}"}[1h])`
    },
    'network': {
      net_rx_mb: `avg_over_time(rate(node_network_receive_bytes_total{system_name="${systemName}"}[5m])[1h:5m]) / 1048576`,
      net_tx_mb: `avg_over_time(rate(node_network_transmit_bytes_total{system_name="${systemName}"}[5m])[1h:5m]) / 1048576`
    },
    'system': {
      load1:  `avg_over_time(node_load1{system_name="${systemName}"}[1h])`,
      load5:  `avg_over_time(node_load5{system_name="${systemName}"}[1h])`,
      load15: `avg_over_time(node_load15{system_name="${systemName}"}[1h])`
    }
  },
  'jmx_exporter': {
    'jvm_heap': {
      heap_used_pct: `avg_over_time(jvm_heap_used_percent{system_name="${systemName}"}[1h])`,
      heap_p95:      `quantile_over_time(0.95, jvm_heap_used_percent{system_name="${systemName}"}[1h])`,
      gc_time_pct:   `avg_over_time(jvm_gc_time_percent{system_name="${systemName}"}[1h])`
    },
    'thread_pool': {
      thread_active: `avg_over_time(jvm_threads_active{system_name="${systemName}"}[1h])`,
      thread_max:    `max_over_time(jvm_threads_active{system_name="${systemName}"}[1h])`,
      rejection_count:`sum_over_time(jvm_thread_pool_rejections_total{system_name="${systemName}"}[1h])`
    },
    'request': {
      req_tps:       `avg_over_time(jvm_requests_per_second{system_name="${systemName}"}[1h])`,
      req_error_rate:`avg_over_time(jvm_request_error_rate{system_name="${systemName}"}[1h])`,
      resp_p95_ms:   `quantile_over_time(0.95, jvm_response_time_ms{system_name="${systemName}"}[1h])`
    },
    'connection_pool': {
      conn_active: `avg_over_time(jvm_connection_pool_active{system_name="${systemName}"}[1h])`,
      conn_wait:   `max_over_time(jvm_connection_pool_waiting{system_name="${systemName}"}[1h])`
    }
  },
  'db_exporter': {
    'db_connections': {
      conn_active_pct:`avg_over_time(db_connections_active_percent{system_name="${systemName}"}[1h])`,
      conn_max:       `max_over_time(db_connections_active{system_name="${systemName}"}[1h])`
    },
    'db_query': {
      tps:             `avg_over_time(db_transactions_per_second{system_name="${systemName}"}[1h])`,
      slow_queries:    `sum_over_time(db_slow_queries_total{system_name="${systemName}"}[1h])`
    },
    'db_cache': {
      cache_hit_rate: `avg_over_time(db_cache_hit_rate_percent{system_name="${systemName}"}[1h])`
    },
    'db_replication': {
      repl_lag_sec: `max_over_time(db_replication_lag_seconds{system_name="${systemName}"}[1h])`
    }
  }
};

const queries = (QUERIES[collectorType] || {})[metricGroup] || {};
const queryList = Object.entries(queries).map(([key, promql]) => ({ key, promql }));

return [{
  json: {
    ...item,
    hour_bucket_iso: hourBucketISO,
    hour_end_ts: hourEnd,
    query_list: queryList,
    prometheus_url: ($env.PROMETHEUS_URL || 'http://prometheus:9090')
  }
}];

// Prometheus 응답 파싱 및 집계 통계 계산
const item = $input.first().json;
const promResponse = $('Prometheus 첫 번째 메트릭 조회').first().json;
const queryList = item.query_list;

// Prometheus /api/v1/query 결과 파싱
const parsePromResult = (data) => {
  if (!data || data.status !== 'success') return {};
  const results = {};
  (data.data?.result || []).forEach(r => {
    const metricName = r.metric?.__name__ || 'unknown';
    const value = parseFloat(r.value?.[1]);
    if (!isNaN(value)) results[metricName] = value;
  });
  return results;
};

// 쿼리가 하나씩 매핑되므로 실제로는 각 query_list 항목을 key로 사용
// (Prometheus or 연산자는 union이므로 결과가 섞임 → 여기서는 단순화하여 첫 값 사용)
const rawValues = parsePromResult(promResponse);

// query_list에서 key → value 매핑 시도
const metricsJson = {};
queryList.forEach(q => {
  const matchingKey = Object.keys(rawValues).find(k => k === q.key) 
    || Object.keys(rawValues)[queryList.indexOf(q)];
  if (rawValues[matchingKey] !== undefined) {
    metricsJson[q.key] = Math.round(rawValues[matchingKey] * 100) / 100;
  }
});

// 이상 감지 조건 (collector_type + metric_group별)
const collectorType = item.collector_type;
const metricGroup = item.metric_group;
let anomalyDetected = false;
let anomalyReason = '';

const checkCpuAnomaly = () => {
  if (metricsJson.cpu_p95 > 75) { anomalyReason = `CPU p95 ${metricsJson.cpu_p95}% > 75%`; return true; }
  if (metricsJson.cpu_avg > 65)  { anomalyReason = `CPU avg ${metricsJson.cpu_avg}% > 65%`; return true; }
  if (metricsJson.iowait > 20)   { anomalyReason = `iowait ${metricsJson.iowait}% > 20%`; return true; }
  return false;
};

const checkMemoryAnomaly = () => {
  if (metricsJson.mem_p95 > 85)     { anomalyReason = `Memory p95 ${metricsJson.mem_p95}% > 85%`; return true; }
  if (metricsJson.mem_used_pct > 80) { anomalyReason = `Memory avg ${metricsJson.mem_used_pct}% > 80%`; return true; }
  return false;
};

const checkJvmAnomaly = () => {
  if (metricsJson.heap_p95 > 85)       { anomalyReason = `JVM heap p95 ${metricsJson.heap_p95}% > 85%`; return true; }
  if (metricsJson.gc_time_pct > 15)    { anomalyReason = `GC time ${metricsJson.gc_time_pct}% > 15%`; return true; }
  if (metricsJson.rejection_count > 0) { anomalyReason = `Thread rejection ${metricsJson.rejection_count}건 발생`; return true; }
  if (metricsJson.req_error_rate > 1)  { anomalyReason = `요청 오류율 ${metricsJson.req_error_rate}% > 1%`; return true; }
  if (metricsJson.resp_p95_ms > 2000)  { anomalyReason = `응답시간 p95 ${metricsJson.resp_p95_ms}ms > 2000ms`; return true; }
  return false;
};

const checkDbAnomaly = () => {
  if (metricsJson.conn_active_pct > 80) { anomalyReason = `DB 연결 ${metricsJson.conn_active_pct}% > 80%`; return true; }
  if (metricsJson.cache_hit_rate < 95)  { anomalyReason = `캐시 히트율 ${metricsJson.cache_hit_rate}% < 95%`; return true; }
  if (metricsJson.repl_lag_sec > 10)    { anomalyReason = `복제 지연 ${metricsJson.repl_lag_sec}초 > 10초`; return true; }
  return false;
};

if (collectorType === 'node_exporter') {
  if (metricGroup === 'cpu')    anomalyDetected = checkCpuAnomaly();
  if (metricGroup === 'memory') anomalyDetected = checkMemoryAnomaly();
  if (metricGroup === 'disk' && metricsJson.disk_util_pct > 80)  { anomalyDetected = true; anomalyReason = `디스크 사용률 ${metricsJson.disk_util_pct}% > 80%`; }
} else if (collectorType === 'jmx_exporter') {
  anomalyDetected = checkJvmAnomaly();
} else if (collectorType === 'db_exporter') {
  anomalyDetected = checkDbAnomaly();
}

// 데이터 없으면 집계 건너뜀
if (Object.keys(metricsJson).length === 0) {
  return [{ json: { ...item, skip: true, reason: 'no_prometheus_data' } }];
}

return [{
  json: {
    ...item,
    metrics_json: JSON.stringify(metricsJson),
    anomaly_detected: anomalyDetected,
    anomaly_reason: anomalyReason,
    skip: false
  }
}];

// LLM 프롬프트 생성 (Template A: 단일 메트릭 이상)
const item = $('집계 계산 및 이상 감지').first().json;
const savedRow = $('Admin API에 기본 집계 저장').first().json;

const systemName = item.system_name;
const displayName = item.display_name;
const hourBucket = item.hour_bucket_iso;
const collectorType = item.collector_type;
const metricGroup = item.metric_group;
const metricsObj = JSON.parse(item.metrics_json || '{}');
const anomalyReason = item.anomaly_reason;

const metricsFormatted = Object.entries(metricsObj)
  .map(([k, v]) => `  ${k}: ${v}`)
  .join('\n');

const prompt = `시스템: ${displayName} (${systemName})
시간대: ${hourBucket} (1시간 집계)
수집기: ${collectorType} / ${metricGroup}
이상 감지 사유: ${anomalyReason}

[현재 시간 집계 메트릭]
${metricsFormatted}

위 메트릭 데이터를 분석하여 다음 JSON 형식으로만 응답하세요:
{
  "severity": "normal 또는 warning 또는 critical 중 하나",
  "trend": "상승 또는 하락 또는 안정 또는 불규칙 (1문장 설명)",
  "prediction": "현재 추세가 지속되면 임계치 도달 예상 (예측 불가 시 null)",
  "root_cause_hypothesis": "가능한 원인 (한국어, 1문장)",
  "recommendation": "권고 조치 (한국어, 1~2문장)"
}`;

return [{
  json: {
    ...item,
    llm_prompt: prompt,
    pg_row_id: savedRow.id
  }
}];

// LLM 응답 파싱 및 요약 텍스트 생성
const llmResponse = $input.first().json;
const prevData = $('LLM 프롬프트 생성').first().json;

let llmResult = {};
try {
  const content = llmResponse?.choices?.[0]?.message?.content 
    || llmResponse?.response 
    || llmResponse?.content 
    || '{}';
  // JSON 블록 추출
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  llmResult = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch(e) {
  llmResult = { severity: 'warning', trend: 'LLM 파싱 오류', prediction: null };
}

const severity    = llmResult.severity    || 'normal';
const trend       = llmResult.trend       || '';
const prediction  = llmResult.prediction  || null;
const rootCause   = llmResult.root_cause_hypothesis || '';
const recommend   = llmResult.recommendation || '';

// Qdrant에 저장할 요약 텍스트
const summaryText = [
  `시스템:${prevData.system_name} 수집기:${prevData.collector_type}/${prevData.metric_group}`,
  `이상: ${prevData.anomaly_reason}`,
  `추세: ${trend}`,
  prediction ? `예측: ${prediction}` : '',
  rootCause ? `원인: ${rootCause}` : ''
].filter(Boolean).join(' | ');

return [{
  json: {
    ...prevData,
    llm_severity:   severity,
    llm_trend:      trend,
    llm_prediction: prediction,
    llm_summary:    `${rootCause} ${recommend}`.trim(),
    llm_model_used: 'internal_llm',
    summary_text:   summaryText,
    needs_proactive_alert: prediction && (severity === 'critical' || prediction.includes('시간'))
  }
}];

// 임계치 도달 예측 Teams Adaptive Card 생성
const item = $('LLM 응답 파싱').first().json;

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          text: `⚠️ [장애 예방] ${item.display_name} 임계치 도달 예측`,
          weight: 'Bolder',
          size: 'Medium',
          color: 'Warning'
        },
        {
          type: 'FactSet',
          facts: [
            { title: '시스템',    value: `${item.display_name} (${item.system_name})` },
            { title: '수집기',    value: `${item.collector_type} / ${item.metric_group}` },
            { title: '이상 감지', value: item.anomaly_reason },
            { title: '추세',      value: item.llm_trend || '-' },
            { title: '예측',      value: item.llm_prediction || '-' },
            { title: '권고 조치', value: item.llm_summary || '-' }
          ]
        }
      ]
    }
  }]
};

return [{ json: { card: JSON.stringify(card), webhook_url: $env.TEAMS_WEBHOOK_URL } }];
